	("LOC_PROMOTION_ADVENTURE_CHAPTER_HD_DESCRIPTION", 											 "Grants [ICON_GREATWRITER] Great Writer Points equal to 50% of defeated unit's [ICON_STRENGTH] Strength."),
	("LOC_PROMOTION_HEROES_CHERISH_HD_NAME", 																 "Heroic Bond"),
	("LOC_PROMOTION_HEROES_CHERISH_HD_DESCRIPTION", 												 "Gain [ICON_FAITH] Faith equal to damage taken."),
