	("LOC_PROMOTION_HEROES_RETURN_HD_DESCRIPTION", 													 "Defeating stronger units provides +10% [ICON_CULTURE] Culture to [ICON_Capital] Capital for 5 turns."),
	("LOC_PROMOTION_IMMORTAL_SEARCH_HD_NAME", 															 "Immortality Quest"),
	("LOC_PROMOTION_IMMORTAL_SEARCH_HD_DESCRIPTION", 												 "If Enkidu falls, all cities gain +10% [ICON_PRODUCTION] Production and [ICON_FAITH] Faith."),
