-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_WONDER_TOURISM_DESCRIPTION",             			 "+20% [ICON_Production] Production toward Medieval, Renaissance, and Industrial era wonders. [ICON_Tourism] Tourism from wonders of any era is +200%. Each time you complete a Wonder, gain [ICON_GREATWRITER] Great Writer, [ICON_GREATARTIST] Great Artist and [ICON_GREATMUSICIAN] Great Musician Points each equals to 20% of its production cost. Each time you active a [ICON_GREATWORK_WRITING] Writing, [ICON_GREATWORK_LANDSCAPE] Art or [ICON_GREATWORK_MUSIC] Music Great Work in a city, complete 10% of the original Wonder cost towards the Wonder that is currently building."),
	-- 黑法国
	("LOC_TRAIT_LEADER_FLYING_SQUADRON_NAME",                         			 "Château de Chenonceau"),
	("LOC_TRAIT_LEADER_FLYING_SQUADRON_DESCRIPTION",                  			 "Receives a free Spy (and extra spy capacity) upon unlocking the Castles technology, Political Philosophy civic, or Supply civic. +1 sight range for Trader, Settler, Builder units and Recon units, +3 sight range for spies. All spies start with a free promotion. Gain 1 level of [ICON_VISLIMITED] Diplomatic Visibility greater than normal with every civilization that they've met."),
	-- 埃利诺
	("LOC_TRAIT_LEADER_ELEANOR_LOYALTY_DESCRIPTION",            			       "In cities built by Eleanor, Art Museums and Archaeological Museums get 3 extra slots, and are automatically themed when all slots are filled. Great Works in Eleanor’s cities each cause -2 Loyalty per turn in foreign cities within 9 tiles. A city that leaves another civilization due to a loss of Loyalty and is currently receiving the most Loyalty per turn from Eleanor's civilization skips the Free City step to join this civilization. May initiate the Judgement of Love project in any city with a Theater Square district."), 
-- =====================================================================================================================================
-- 希腊
-- =====================================================================================================================================
	-- 男希腊
	("LOC_TRAIT_LEADER_SURROUNDED_BY_GLORY_DESCRIPTION",     			           "+5% [ICON_Culture] Culture per city-state you are the Suzerain of. After building an Acropolis District, the first [ICON_Envoy] Envoy you send to each city-state counts as two [ICON_Envoy] Envoys."),
	-- 女希腊
	("LOC_TRAIT_LEADER_THERMOPYLAE_DESCRIPTION",            			           "Combat victories provide [ICON_Culture] Culture equal to 50% of the [ICON_Strength] Combat Strength of the defeated unit. (on Standard Speed) +1 [ICON_Strength] Combat Strength for every Military Policy slotted. Receive a free anti-cavalry unit when the Acropolis district is constructed."),
-- =====================================================================================================================================
-- 挪威
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_EARLY_OCEAN_NAVIGATION_DESCRIPTION", 			     "Fishing Boats provide +1 [ICON_Production] Production. Naval melee units heal in neutral territory. Units ignore additional [ICON_Movement] Movement costs from embarking and disembarking."),
	-- 劫掠挪威
	("LOC_LEADER_HARDRADA_ORIGINAL_NAME",                         			     "Harald Hardrada (Heimskringla)"),
	("LOC_TRAIT_LEADER_THUNDERBOLT_EXPANSION2_DESCRIPTION",      			       "Allows coastal raiding for all naval units. Pillaging costs only 1 [ICON_MOVEMENT] Movement point, and coastal raiding does not cost [ICON_MOVEMENT] Movement point. In addition to normal pillage gains, receive [ICON_SCIENCE] Science from pillaging Fishing Boats, receive [ICON_CULTURE] Culture from pillaging Fishery. Units gain the ability to enter Deep Ocean tiles after researching the Shipbuilding technology. Ancient and Classical era naval units gain +1 [ICON_MOVEMENT] Movement. Gain the Berserker unique unit with Metal Casting."),
	-- 瓦良格
	("LOC_LEADER_HARALD_ALT_NAME",                              			       "Harald Hardrada (Varangian)"),
	("LOC_TRAIT_LEADER_HARALD_ALT_NAME",                       			         "Varangian Adventure"),
	("LOC_TRAIT_LEADER_HARALD_ALT_XP_DESCRIPTION",            			         "At the end of your turn, gain 1 [ICON_GOLD] Gold for each newly discoverd tile. Goody huts visited by your units reward extra 30 [ICON_GOLD] Gold."),
-- =====================================================================================================================================
-- 美国
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_FOUNDING_FATHERS_NAME",                         "Manifest Destiny"),
	("LOC_TRAIT_CIVILIZATION_FOUNDING_FATHERS_EXPANSION2_DESCRIPTION",       "Border expansion rate is 100% faster. At the end of your turn, gain 10 [ICON_GOLD] Gold from each newly expanded tile across your empire; gain extra 20 [ICON_GOLD] Gold if tile has any resource. Can use [ICON_GOLD] Gold as 4 times the [ICON_FOOD] Food cost to gain a [ICON_CITIZEN] Citizen."),
	("LOC_AMERICA_NO_GOLD_WARNING",                                          "[ICON_GOLD] [COLOR_RED]Gold is not enough[ENDCOLOR]"),
	("LOC_AMERICA_NO_CITY_WARNING",                                          "[COLOR_RED]City doesn't exist.[ENDCOLOR]"),
	("LOC_AMERECA_BUTTON_DESCRIPTION",                                       "Can use [ICON_GOLD] Gold to gain a [ICON_CITIZEN] Citizen."),
	("LOC_AMERECA_BUTTON_DETAIL",                                            "Cost {1_num} [ICON_GOLD] Gold"),
	-- 武老美
	("LOC_TRAIT_LEADER_ROOSEVELT_COROLLARY_ROUGH_RIDER_DESCRIPTION",         "Units receive +5 [ICON_Strength] Combat Strength on their home continent. When you start a [ICON_TRADEROUTE] Trade Route to a City-State, send an [ICON_ENVOY] Envoy to this City-State. Every specialty district in the origin city provide +1 [ICON_SCIENCE] Science and +2 [ICON_GOLD] Gold for your [ICON_TRADEROUTE] Trade Routes to any city-state. Upon conquering another Civilization's Original [ICON_CAPITAL] Capital city, if this Civilization is still in the game, take over immediately all the City-States it is the Suzerain of. Gain the Rough Rider unique unit with Rifling."),
	-- 文老美
	("LOC_TRAIT_LEADER_ANTIQUES_AND_PARKS_DESCRIPTION",                      "Breathtaking tiles receive +1 [ICON_SCIENCE] Science and +1 [ICON_CULTURE] Culture. All tiles in a city with a National Park are +1 Appeal."),
	-- 林肯
	("LOC_TRAIT_LEADER_LINCOLN_EXPANSION_DESCRIPTION",                       "Industrial Zones give +2 [ICON_Amenities] Amenities. Receive a free Builder every time you finish a Industrial Zone. Enable Liberating the builders, which removes the unit and gives +1 [ICON_PRODUCTION] Production adjacency bonus to this Industrial Zone for each builder charge the unit has, and gains 1 [ICON_CITIZEN] Citizen if you first do it in a city."),
	("LOC_UNITCOMMAND_LIBERATION_LINCOLN_NAME",                              "Liberate"),
	("LOC_UNITCOMMAND_LIBERATION_LINCOLN_DESCRIPTION",                       "Liberate this unit to give +1 [ICON_PRODUCTION] Production adjacency bonus to this Industrial Zone for each builder charge the unit has, and gain 1 [ICON_CITIZEN] citizen if you first do it in a city."),
	("LOC_UNITCOMMAND_LIBERATION_LINCOLN_DISABLED_TT",                       "Must be located in the Industrial Zone, and have [ICON_MOVEMENT] Movement left."),
-- =====================================================================================================================================
-- 大哥伦比亚
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_EJERCITO_PATRIOTA_DESCRIPTION",                 "+1 [ICON_Movement] Movement to all units. Promoting a unit does not end that unit’s turn. Planations Culture Bomb nearby neutral territory, and receive +1 [ICON_CULTURE] Culture."),
-- =====================================================================================================================================
-- 朝鲜
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_THREE_KINGDOMS_NAME",                           "Chiphyonjon"),
	("LOC_TRAIT_CIVILIZATION_THREE_KINGDOMS_DESCRIPTION",                    "Receive +1 [Icon_Governor] Governor Title each time a Seowon district or buildings inside a Seowon District is constructed in your [ICON_Capital] Capital."),
	-- 女朝鲜
	("LOC_LEADER_SEONDEOK_NAME",                                             "Kim Deokman"),
	("LOC_TRAIT_LEADER_HWARANG_DESCRIPTION",                                 "+5 [Icon_Housing] Housing and +20 Loyalty per turn for your Capital and cities with an assigned Governor. -20 Loyalty per turn and -50% to all yields for cities that are not your Capital and do not have an assigned Governors. [NEWLINE]+25% [ICON_PRODUCTION] Production towards Districts and Buildings for cities that have a Seowon district. [NEWLINE]+15% [ICON_Production] Production and +15% [ICON_FOOD] Food for Cities with a Tier 1 building of Campus district. [NEWLINE]+100% districts adjacency bonuses to all Districts for Cities with a Tier 2 building of Campus district. [NEWLINE]Each [ICON_CITIZEN] citizen provieds +1 all yields for Cities with a Tier 3 building of Campus district. [NEWLINE]+10% to all yields for Cities with a Tier 4 building of Campus district."),
	-- 男朝鲜
	("LOC_LEADER_SEJONG_NAME",                                               "Yi Do"),
	("LOC_TRAIT_LEADER_SEJONG_NAME",                                         "Hunminjeongeum"),
	("LOC_AGENDA_SEJONG_NAME",                                               "Yao and Shun of Choson"),
	("LOC_TRAIT_LEADER_SEJONG_DESCRIPTION",                                  "Buildings in Campus or Theater districts provide [ICON_SCIENCE] Science or [ICON_CULTURE] Culture equal to their basic yield bonus of [ICON_CULTURE] Culture or [ICON_SCIENCE] Science. Seowon and buildings in Seowon can hold a [ICON_GreatWork_Writing] Great Work of Writing. Earn a Codifier after building the Seowon or any building in Seowon. After a [ICON_GREATSCIENTIST] Great Scientist is recruited, apply the Activated Effect once to your [ICON_CAPITAL] Capital."),
-- =====================================================================================================================================
-- 克里
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_CREE_TRADE_GAIN_TILES_DESCRIPTION",             "+1 [ICON_TradeRoute] Trade Route capacity and a free Trader with the Pottery technology. +1 [ICON_TradeRoute] Trade Route capacity and a free Trader with the State Workforce civic. Unclaimed tiles within 3 tiles of a Cree city come under Cree control when a Trader first moves into them."),
	("LOC_LEADER_POUNDMAKER_ABILITY_NAME",                                   "Favorable Terms"),
	("LOC_LEADER_POUNDMAKER_ABILITY_DESCRIPTION",                            "All Alliance types provide Shared Visibility.[NEWLINE]Your outgoing [ICON_TradeRoute] Trade Routes grant you +1 [ICON_Food] Food per Fishing Boat, Camp or Pasture improvements at the destination. [ICON_TradeRoute] Trade Routes sent to your cities grant you +1 [ICON_Gold] Gold per Fishing Boat, Camp or Pasture improvements at the destination."),
-- =====================================================================================================================================
-- 马里
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_MALI_GOLD_DESERT_DESCRIPTION",                  "City Centers gain +1 [ICON_FAITH] Faith and +1 [ICON_FOOD] Food for every adjacent Desert and Desert Hills tiles. Mines receive -1 [ICON_PRODUCTION] Production and +4 [ICON_GOLD] Gold. May purchase Commercial Hub district buildings with [ICON_Faith] Faith. -30% production speed toward constructing buildings or training units."),
	-- 文马里
	("LOC_TRAIT_LEADER_SAHEL_MERCHANTS_DESCRIPTION",                         "Earn extra 10 [ICON_GOLD] Gold for each [ICON_GLORY_NORMAL_AGE] era score earned. International [ICON_TradeRoute] Trade Routes gain +1 [ICON_GOLD] Gold for every flat Desert tiles in the origin city. Receive +1 [ICON_TradeRoute] Trade Capacity every time you enter a Golden Age."),
	-- 武马里
	("LOC_TRAIT_LEADER_SUNDIATA_KEITA_NAME",                                 "Founder of Mali"),
	("LOC_TRAIT_LEADER_SUNDIATA_KEITA_DESCRIPTION",                          "Units are 15% cheaper to purchase with [ICON_GOLD] Gold and [ICON_FAITH] Faith, and can move and attack immediately."),
-- =====================================================================================================================================
-- 加拿大
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_FACES_OF_PEACE_NAME",             			 				 "The Last Best West"),
	("LOC_TRAIT_CIVILIZATION_FACES_OF_PEACE_DESCRIPTION",                    "Allows Farms to be built on Tundra terrain. After Civil Engineering is unlocked Farms can be built on Tundra Hills. Basic Improvements on Tundra, Snow and these Hills provide +1 [ICON_FOOD] Food and [ICON_PRODUCTION] Production. Reduces the purchase cost of tiles in these terrain types by 50%."),
	("LOC_TRAIT_LEADER_LAST_BEST_WEST_NAME",             			 			 				 "Four Faces of Peace"),
	("LOC_TRAIT_LEADER_LAST_BEST_WEST_DESCRIPTION",                          "Cannot declare war on City-States or surprise wars. Surprise wars cannot be declared on you. Your cities earn +15% [ICON_Culture] Culture and +25% [ICON_Tourism] Tourism across your empire whenever you are not at war with any major civilization. When you dispersed a Barbarian Outpost, receive a builder reward in addition."),
-- =====================================================================================================================================
-- 俄罗斯
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_MOTHER_RUSSIA_EXPANSION2_DESCRIPTION",          "+1 [ICON_Food] Food for all Tundra Districts. Extra territory upon founding cities. +1 [ICON_Faith] Faith and +1 [ICON_Production] Production from Tundra. Units do not receive damage from Blizzards. Civilizations that are at war with Russia receive +100% unit damage from Blizzards in Russian territory."),
	("LOC_TRAIT_LEADER_GRAND_EMBASSY_NAME",                                  "Pater Patriae"),
	("LOC_TRAIT_LEADER_GRAND_EMBASSY_DESCRIPTION",                           "Can purchase buildings in Industrial Zone with [ICON_FAITH] Faith. -10% [ICON_FAITH] Faith cost when patronizing [ICON_GREATPERSON] Great Person."),
-- =====================================================================================================================================
-- 斯基泰
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_EXTRA_LIGHT_CAVALRY_DESCRIPTION",               "Begin the game with the Animal Husbandry technology unlocked. +1 [Icon_Production] Production for all Pastures across the Nation. Improved [ICON_RESOURCE_HORSES] Horses accumulate 3 more resources per turn. Receive a second light cavalry unit or Saka Horse Archer each time you train a light cavalry unit or Saka Horse Archer."),
-- =====================================================================================================================================
-- 澳大利亚
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_LAND_DOWN_UNDER_DESCRIPTION",                   "Pastures trigger a Culture Bomb, and receive +1 [ICON_CULTURE] Culture. Yields from Campuses, Commercial Hubs, Holy Sites and Theater Squares are +1 in tiles with Charming Appeal, +3 in Breathtaking."),
	("LOC_TRAIT_LEADER_CITADEL_CIVILIZATION_NAME",                           "Citadel of Civilization"),
-- =====================================================================================================================================
-- 德国
-- =====================================================================================================================================
	("LOC_TRAIT_CIVILIZATION_IMPERIAL_FREE_CITIES_DESCRIPTION",              "Each city can build one more district than usual. +1 [ICON_Science] Science and [ICON_Culture] Culture for cities that have Specialty Districts."),
	("LOC_TRAIT_LEADER_HOLY_ROMAN_EMPEROR_DESCRIPTION",                      "After Early Warfare civic is researched, receive an additional Military policy slot. After Encampment district is first built, receive an additional Military policy slot. Encampment district receives an additional standard adjacency bonus for being adjacent to another district, and [ICON_FAITH] Faith equal to its adjacency bonus. Encampment district provides +1 [ICON_PRODUCTION] Production, +1 [ICON_FAITH] Faith to resource plots in the city. Districts and land units can be purchased with [ICON_FAITH] Faith in cities with a [ICON_GOVERNOR] Governor."),
-- =====================================================================================================================================
