	"LOC_TRAIT_LEADER_FOUNDER_CARTHAGE_DESCRIPTION", "Alliance level reaches Level 3 in one turn. Gain the unique Move Capital project, when first move to a new continent, +50% border expansion rate and send an [ICON_Envoy] Envoy to each City-State on that continent. Construction of Diplomatic Quarter and its buildings complete immediately."
where exists (select Tag from LocalizedText where Tag = 'LOC_CIVILIZATION_ETHIOPIA_NAME');

insert or replace into LocalizedText (Language, Tag, Text) select
	"zh_Hans_CN", "LOC_TRAIT_LEADER_FOUNDER_CARTHAGE_DESCRIPTION", "同盟以最快的速度升级。建造外交区和其中的建筑时可以立刻完成。由你建立的拥有U型港的城市中可进行“迁都”项目，将原始 [ICON_Capital] 首都迁移到该城市。每次将 [ICON_Capital] 首都迁移到一个未曾建都的大陆时，所有城市边界扩张速度+50%，并向该大陆的每个城邦派遣1名 [ICON_ENVOY] 使者。"
where exists (select Tag from LocalizedText where Tag = 'LOC_CIVILIZATION_ETHIOPIA_NAME');
